import{_ as d,I as i,o as a,c as n,a5 as e,b as o,w as s,a as l,J as c,a6 as h,a8 as p}from"./chunks/framework.BhwUwRYb.js";const f=JSON.parse('{"title":"艺术家","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"artist.md","filePath":"artist.md"}'),g={name:"artist.md"};function b(A,t,_,u,m,k){const r=i("Mermaid");return a(),n("div",null,[t[1]||(t[1]=e('<h1 id="艺术家" tabindex="-1">艺术家 <a class="header-anchor" href="#艺术家" aria-label="Permalink to “艺术家”">​</a></h1><p>相关文档：<a href="/music-free-site/album.html">专辑</a> · <a href="/music-free-site/music.html">音乐管理</a> · <a href="/music-free-site/plugin-orchestration.html">插件编排</a> · <a href="/music-free-site/opensubsonic-api.html">OpenSubsonic API</a></p><p><img src="'+p+'" alt=""></p><h2 id="_1-模块概述" tabindex="-1">1. 模块概述 <a class="header-anchor" href="#_1-模块概述" aria-label="Permalink to “1. 模块概述”">​</a></h2><p><strong>艺术家模块</strong>负责曲库中艺术家的浏览、展示、元数据补全与头像管理。功能分布在两个入口：</p><table tabindex="0"><thead><tr><th>入口</th><th>路径</th><th>侧栏名称</th><th>主要用户</th></tr></thead><tbody><tr><td><strong>艺术家浏览</strong></td><td><code>/artists</code>、<code>/artists/:id</code></td><td>艺术家</td><td>所有登录用户</td></tr><tr><td><strong>艺术家管理</strong></td><td><code>/admin/artists</code></td><td>艺术家管理</td><td>管理员</td></tr></tbody></table>',6)),(a(),o(h,null,{default:s(()=>[c(r,{id:"mermaid-63",class:"mermaid",graph:"flowchart%20TB%0A%20%20subgraph%20user%20%5B%E7%94%A8%E6%88%B7%E7%AB%AF%20%2Fartists%5D%0A%20%20%20%20L%5B%E8%89%BA%E6%9C%AF%E5%AE%B6%E5%88%97%E8%A1%A8%5D%0A%20%20%20%20D%5B%E8%89%BA%E6%9C%AF%E5%AE%B6%E8%AF%A6%E6%83%85%5D%0A%20%20%20%20P%5B%E6%92%AD%E6%94%BE%E5%85%A8%E9%83%A8%E6%AD%8C%E6%9B%B2%5D%0A%20%20end%0A%20%20subgraph%20admin%20%5B%E7%AE%A1%E7%90%86%E7%AB%AF%5D%0A%20%20%20%20B%5B%E6%89%B9%E9%87%8F%E5%8C%B9%E9%85%8D%E5%A4%B4%E5%83%8F%20%2Fadmin%2Fartists%5D%0A%20%20%20%20M%5B%E5%8D%95%E8%89%BA%E6%9C%AF%E5%AE%B6%E5%8C%B9%E9%85%8D%20%2Fartists%2F%3Aid%5D%0A%20%20end%0A%20%20subgraph%20plugins%20%5BWASM%20%E6%8F%92%E4%BB%B6%20GetArtistInfo%5D%0A%20%20%20%20MB%5BMusicBrainz%5D%0A%20%20%20%20NE%5B%E7%BD%91%E6%98%93%E4%BA%91%5D%0A%20%20%20%20QQ%5BQQ%20%E9%9F%B3%E4%B9%90%5D%0A%20%20%20%20SP%5BSpotify%5D%0A%20%20%20%20LF%5BLast.fm%5D%0A%20%20end%0A%20%20subgraph%20storage%20%5B%E5%AD%98%E5%82%A8%5D%0A%20%20%20%20DB%5B(artists%20%E8%A1%A8)%5D%0A%20%20%20%20CV%5Bcover_path%20%E5%A4%B4%E5%83%8F%E6%96%87%E4%BB%B6%5D%0A%20%20end%0A%20%20L%20--%3E%20D%0A%20%20D%20--%3E%20P%0A%20%20B%20--%3E%20plugins%0A%20%20M%20--%3E%20plugins%0A%20%20plugins%20--%3E%20CV%0A%20%20plugins%20--%3E%20DB%0A%20%20D%20--%3E%20DB%0A%20%20L%20--%3E%20DB%0A"})]),fallback:s(()=>[...t[0]||(t[0]=[l(" Loading... ",-1)])]),_:1})),t[2]||(t[2]=e(`<p>扫描本地媒体库后，系统按歌曲标签中的 <strong>艺术家名</strong> 聚合生成 <code>artists</code> 记录；专辑与艺术家通过 <strong><code>album_artists</code></strong> 关联表支持「主艺术家 + 参与艺术家」等多艺人专辑。</p><h2 id="_2-访问与权限" tabindex="-1">2. 访问与权限 <a class="header-anchor" href="#_2-访问与权限" aria-label="Permalink to “2. 访问与权限”">​</a></h2><h3 id="_2-1-艺术家浏览-用户端" tabindex="-1">2.1 艺术家浏览（用户端） <a class="header-anchor" href="#_2-1-艺术家浏览-用户端" aria-label="Permalink to “2.1 艺术家浏览（用户端）”">​</a></h3><ul><li><strong>列表</strong>：<code>/artists</code> — 网格展示艺术家卡片，支持关键词搜索与分页。</li><li><strong>详情</strong>：<code>/artists/:id</code> — 头像、专辑列表、「播放全部歌曲」等。</li><li><strong>权限</strong>：需登录；浏览与播放对所有用户开放。</li></ul><h3 id="_2-2-艺术家管理-管理端" tabindex="-1">2.2 艺术家管理（管理端） <a class="header-anchor" href="#_2-2-艺术家管理-管理端" aria-label="Permalink to “2.2 艺术家管理（管理端）”">​</a></h3><ul><li><strong>批量匹配头像</strong>：<code>/admin/artists</code>（侧栏「艺术家管理」）。</li><li><strong>权限</strong>：仅管理员（<code>requiresAdmin</code>）。</li><li><strong>旧路径</strong>：<code>/artists/photo-batch-match</code> 重定向至 <code>/admin/artists</code>。</li></ul><h3 id="_2-3-单艺术家刮削-管理端操作-用户端页面" tabindex="-1">2.3 单艺术家刮削（管理端操作，用户端页面） <a class="header-anchor" href="#_2-3-单艺术家刮削-管理端操作-用户端页面" aria-label="Permalink to “2.3 单艺术家刮削（管理端操作，用户端页面）”">​</a></h3><ul><li>在 <strong><code>/artists/:id</code></strong> 详情页，管理员可见 <strong>「匹配」</strong> 按钮，用于拉取外部目录候选并人工确认保存（无需进入 <code>/admin/artists</code>）。</li></ul><h2 id="_3-艺术家浏览" tabindex="-1">3. 艺术家浏览 <a class="header-anchor" href="#_3-艺术家浏览" aria-label="Permalink to “3. 艺术家浏览”">​</a></h2><h3 id="_3-1-艺术家列表" tabindex="-1">3.1 艺术家列表 <a class="header-anchor" href="#_3-1-艺术家列表" aria-label="Permalink to “3.1 艺术家列表”">​</a></h3><ul><li><strong>展示</strong>：卡片网格，含头像（若有）、名称、专辑数量。</li><li><strong>搜索</strong>：按名称模糊匹配，回车或点击搜索；查询参数同步到 URL（<code>q</code>、<code>page</code>、<code>pageSize</code>）。</li><li><strong>分页</strong>：默认每页 20 条，可翻页浏览大库。</li><li><strong>空状态</strong>：尚未扫描媒体库时提示「扫描音乐库后即可按艺术家浏览」。</li></ul><h3 id="_3-2-艺术家详情" tabindex="-1">3.2 艺术家详情 <a class="header-anchor" href="#_3-2-艺术家详情" aria-label="Permalink to “3.2 艺术家详情”">​</a></h3><table tabindex="0"><thead><tr><th>区域</th><th>说明</th></tr></thead><tbody><tr><td>头部</td><td>头像、<code>专辑数</code>、<strong>播放全部歌曲</strong>（将该艺术家下各专辑曲目加入播放队列）</td></tr><tr><td>专辑区</td><td>网格展示关联专辑；点击进入 <code>/albums/:id</code></td></tr><tr><td>元数据</td><td>出生年月、国籍/地区、个人简介等（刮削保存后可见）</td></tr></tbody></table><p><strong>专辑关联规则</strong>：详情页专辑列表包含：</p><ul><li>以该艺术家为 <strong>主艺术家</strong>（<code>albums.artist_id</code>）的专辑；</li><li>通过 <strong><code>album_artists</code></strong> 标记为参与者的专辑（<code>role: participant</code>）。</li></ul><p>因此合作专辑、群星合辑会出现在相关艺术家名下。</p><h3 id="_3-3-管理员维护操作-详情-列表" tabindex="-1">3.3 管理员维护操作（详情 / 列表） <a class="header-anchor" href="#_3-3-管理员维护操作-详情-列表" aria-label="Permalink to “3.3 管理员维护操作（详情 / 列表）”">​</a></h3><table tabindex="0"><thead><tr><th>操作</th><th>条件</th><th>说明</th></tr></thead><tbody><tr><td>删除艺术家</td><td>管理员 + <strong>专辑数为 0</strong></td><td>列表卡片或详情上下文；有专辑时不可删</td></tr></tbody></table><p>删除为数据库记录清理，<strong>不删除磁盘上的音频文件</strong>。</p><h2 id="_4-单艺术家匹配-刮削确认" tabindex="-1">4. 单艺术家匹配（刮削确认） <a class="header-anchor" href="#_4-单艺术家匹配-刮削确认" aria-label="Permalink to “4. 单艺术家匹配（刮削确认）”">​</a></h2><h3 id="_4-1-能做什么" tabindex="-1">4.1 能做什么 <a class="header-anchor" href="#_4-1-能做什么" aria-label="Permalink to “4.1 能做什么”">​</a></h3><p>管理员在艺术家详情页点击 <strong>「匹配」</strong> 后：</p><ol><li>后端按编排顺序调用已启用、支持 <strong>艺术家维度</strong> 的刮削插件（<code>GetArtistInfo</code>）。</li><li>汇总各插件返回的 <strong>候选列表</strong>（可能多条），弹窗展示： <ul><li>艺术家名、头像预览、出生年月、国籍/地区、简介、来源插件。</li></ul></li><li>管理员选中一条候选，点击 <strong>「保存确认」</strong> 写入数据库。</li></ol><p><strong>特点</strong>：刮削阶段 <strong>不自动写库</strong>；必须人工确认，避免误匹配。</p><h2 id="_5-批量匹配艺术家照片-管理端" tabindex="-1">5. 批量匹配艺术家照片（管理端） <a class="header-anchor" href="#_5-批量匹配艺术家照片-管理端" aria-label="Permalink to “5. 批量匹配艺术家照片（管理端）”">​</a></h2><h3 id="_5-1-能做什么" tabindex="-1">5.1 能做什么 <a class="header-anchor" href="#_5-1-能做什么" aria-label="Permalink to “5.1 能做什么”">​</a></h3><p>对曲库中<strong>大量艺术家</strong>自动拉取头像，适合在初次建库或批量补图时使用。页面路径：<strong><code>/admin/artists</code></strong>。</p><p>核心能力：</p><ul><li>按条件筛选目标艺术家（默认仅 <strong>缺失头像</strong>）。</li><li>后台异步任务，实时进度与逐条结果。</li><li>多插件 <strong>短路策略</strong>：每位艺术家按插件顺序尝试，<strong>任一插件成功即停止</strong>。</li><li>匹配成功时 <strong>立即写库</strong>，无需额外点击「应用」。</li><li>支持对失败/跳过项 <strong>重试</strong>（生成新任务，仅包含未成功艺术家）。</li></ul><h3 id="_5-2-任务配置" tabindex="-1">5.2 任务配置 <a class="header-anchor" href="#_5-2-任务配置" aria-label="Permalink to “5.2 任务配置”">​</a></h3><table tabindex="0"><thead><tr><th>选项</th><th>默认</th><th>说明</th></tr></thead><tbody><tr><td>仅处理缺失头像</td><td>开启</td><td>只处理 <code>cover_art</code> 为空的艺术家</td></tr><tr><td>允许覆盖已有头像</td><td>关闭</td><td>开启后也会处理已有头像的艺术家</td></tr><tr><td>插件顺序</td><td>空（后端默认）</td><td>多选；仅列出支持 <code>GetArtistInfo</code> 且已启用的插件</td></tr></tbody></table><p>点击 <strong>「创建批量匹配任务」</strong> 后返回 <code>taskId</code>，页面自动轮询状态（约 3 秒）并刷新结果列表。</p><h3 id="_5-3-任务状态与结果" tabindex="-1">5.3 任务状态与结果 <a class="header-anchor" href="#_5-3-任务状态与结果" aria-label="Permalink to “5.3 任务状态与结果”">​</a></h3><p><strong>状态汇总</strong>：任务 ID、状态（<code>pending</code> / <code>running</code> / <code>success</code> / <code>failed</code>）、进度百分比、总数、已处理、成功、失败、跳过。</p><p><strong>逐条结果</strong>：艺术家名、状态标签、所用插件、匹配到的封面 key（成功时可预览缩略图）。失败项悬停可查看 <strong>错误码与错误信息</strong>。</p><p><strong>重试</strong>：当 <code>失败 + 跳过 &gt; 0</code> 时，可点击 <strong>「重试失败/跳过项」</strong>，系统为这批艺术家创建新任务。</p><h3 id="_5-4-匹配逻辑要点" tabindex="-1">5.4 匹配逻辑要点 <a class="header-anchor" href="#_5-4-匹配逻辑要点" aria-label="Permalink to “5.4 匹配逻辑要点”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>对每位艺术家:</span></span>
<span class="line"><span>  按 pluginOrder（或默认顺序）遍历插件</span></span>
<span class="line"><span>    调用 GetArtistInfo(artistName)</span></span>
<span class="line"><span>    若返回合法 coverArt key → 标记成功，写库，停止尝试后续插件</span></span>
<span class="line"><span>    若失败 / 空结果 / URL 头像 / key 格式非法 → 尝试下一个插件</span></span>
<span class="line"><span>  全部插件失败 → 标记 failed</span></span></code></pre></div><ul><li>合法 <code>coverArt</code> key 格式：<code>sha256-[64位小写十六进制]</code>（可带扩展名由存储层解析）。</li><li>并发：按 CPU 核心数等工作线程池处理，单任务内进度持续回写。</li></ul><h3 id="_5-5-与单艺术家「匹配」的区别" tabindex="-1">5.5 与单艺术家「匹配」的区别 <a class="header-anchor" href="#_5-5-与单艺术家「匹配」的区别" aria-label="Permalink to “5.5 与单艺术家「匹配」的区别”">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>详情页「匹配」</th><th>批量匹配头像</th></tr></thead><tbody><tr><td>入口</td><td><code>/artists/:id</code></td><td><code>/admin/artists</code></td></tr><tr><td>范围</td><td>当前 1 位艺术家</td><td>库内符合条件的全部（或重试子集）</td></tr><tr><td>确认方式</td><td>弹窗人工选择候选</td><td>自动取插件首条合法结果</td></tr><tr><td>元数据</td><td>可保存简介、国籍、出生年月等</td><td>主要更新头像（<code>coverArt</code>）</td></tr><tr><td>写库时机</td><td>用户点击「保存确认」</td><td>每条匹配成功时立即写库</td></tr></tbody></table><h2 id="_6-opensubsonic-与第三方客户端" tabindex="-1">6. OpenSubsonic 与第三方客户端 <a class="header-anchor" href="#_6-opensubsonic-与第三方客户端" aria-label="Permalink to “6. OpenSubsonic 与第三方客户端”">​</a></h2><p>MusicFree 作为 OpenSubsonic 服务器，向客户端暴露标准艺术家相关接口，与 Web UI 共用同一曲库数据：</p><table tabindex="0"><thead><tr><th>接口</th><th>用途</th></tr></thead><tbody><tr><td><code>getArtists</code></td><td>按首字母索引列出艺术家</td></tr><tr><td><code>getArtist</code></td><td>艺术家及其专辑目录</td></tr><tr><td><code>getArtistInfo</code> / <code>getArtistInfo2</code></td><td>简介、图片 URL、相似艺术家、热门歌曲等</td></tr><tr><td><code>getIndexes</code></td><td>索引浏览</td></tr><tr><td><code>getMusicDirectory</code></td><td>目录树导航（媒体源 / 艺术家 / 专辑层级）</td></tr><tr><td><code>getCoverArt</code></td><td><code>id=ar-{artistId}</code> 获取艺术家封面</td></tr></tbody></table><p>Web 前端头像 URL 形如：<code>/rest/api/v1/artists/{id}/avatar</code>（需认证）。</p><p>Navidrome 兼容 REST（实验性）：<code>GET /api/artist</code>、<code>GET /api/artist/:id</code>。</p><h2 id="_7-典型工作流" tabindex="-1">7. 典型工作流 <a class="header-anchor" href="#_7-典型工作流" aria-label="Permalink to “7. 典型工作流”">​</a></h2><h3 id="_7-1-新库补全艺术家头像" tabindex="-1">7.1 新库补全艺术家头像 <a class="header-anchor" href="#_7-1-新库补全艺术家头像" aria-label="Permalink to “7.1 新库补全艺术家头像”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>扫描媒体源 → 生成 artists</span></span>
<span class="line"><span>    → /admin/plugin 启用 netease / musicbrainz 等</span></span>
<span class="line"><span>    → /admin/artists → 勾选「仅缺失头像」→ 创建批量匹配任务</span></span>
<span class="line"><span>    → 等待任务完成 → 在 /artists 浏览验证头像</span></span></code></pre></div><h3 id="_7-2-修正单个艺术家的简介与头像" tabindex="-1">7.2 修正单个艺术家的简介与头像 <a class="header-anchor" href="#_7-2-修正单个艺术家的简介与头像" aria-label="Permalink to “7.2 修正单个艺术家的简介与头像”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>/artists → 进入详情 → 「匹配」</span></span>
<span class="line"><span>    → 在候选表中对比来源与简介 → 保存确认</span></span>
<span class="line"><span>    → 刷新后查看头像与元数据</span></span></code></pre></div><h3 id="_7-3-客户端浏览" tabindex="-1">7.3 客户端浏览 <a class="header-anchor" href="#_7-3-客户端浏览" aria-label="Permalink to “7.3 客户端浏览”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Feishin / Ultrasonic 等连接 OpenSubsonic</span></span>
<span class="line"><span>    → getArtists / getArtist 浏览</span></span>
<span class="line"><span>    → getArtistInfo 查看简介与相似艺术家</span></span></code></pre></div><h2 id="_8-常见问题" tabindex="-1">8. 常见问题 <a class="header-anchor" href="#_8-常见问题" aria-label="Permalink to “8. 常见问题”">​</a></h2><p><strong>Q：列表里艺术家没有头像？</strong><br> A：尚未刮削或批量匹配；到 <code>/admin/artists</code> 跑批量任务，或在详情页用「匹配」手动确认。确认 <code>music.cover_path</code> 配置正确且插件已启用。</p><p><strong>Q：批量任务大量失败？</strong><br> A：检查插件配置（API Key、限流）；查看结果条目的错误信息；常见原因包括插件返回 URL 而非本地 <code>sha256-</code> 文件名、艺术家名称为空或 <code>Unknown Artist</code>。</p><p><strong>Q：删除艺术家失败？</strong><br> A：仅当 <strong>专辑数为 0</strong> 时可删；需先移除或合并其专辑关联。</p>`,57))])}const B=d(g,[["render",b]]);export{f as __pageData,B as default};
